```ts
/**
 * 디바운스(연속 호출 억제) 래퍼를 만들어요.
 * 마지막 호출로부터 wait(ms) 이내에 다시 호출이 들어오면 이전 호출은 취소돼요.
 * 검색창 입력처럼 빈번한 이벤트를 묶어 처리할 때 써요.
 *
 * @param fn 래핑할 원본 함수.
 * @param wait 마지막 호출로부터의 대기 시간(밀리초).
 * @returns 동일한 시그니처의 디바운스된 함수.
 */
export async function debounce<T extends (...args: any[]) => any>(fn: T, wait: number) {
  // closure로 가장 최근 timer 핸들을 보관해요.
  let timer: ReturnType<typeof setTimeout> | null = null;
  return (...args: Parameters<T>) => {
    // 새 호출이 들어오면 이전 예약을 취소해요.
    if (timer) clearTimeout(timer);
    timer = setTimeout(() => fn(...args), wait);
  };
}
```
